import React from 'react';
import { Card, CardContent, Box, Typography, Stack, CircularProgress } from '@mui/material';
import response from './response.json';

interface CurrentEpisode {
  title: string;
  host: string;
  duration: number;
  progress: number;
  progressPercent: number;
}

interface ListeningStats {
  totalHours: number;
  episodesCompleted: number;
}

interface PodcastData {
  currentEpisode: CurrentEpisode;
  listeningStats: ListeningStats;
}

export default function Widget() {
  const podcastData = response.data as PodcastData;
  const { currentEpisode, listeningStats } = podcastData;
  const remainingTime = currentEpisode.duration - currentEpisode.progress;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#222222' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FF5722', mb: 0.5 }}>
              Now Playing
            </Typography>
            <Typography variant="h5" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
              {currentEpisode.title}
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Host: {currentEpisode.host}
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" alignItems="center">
              <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                Progress
              </Typography>
              <Typography variant="caption" sx={{ color: '#B0BEC5' }}>
                {Math.floor(remainingTime / 60)} min left
              </Typography>
            </Stack>
            <CircularProgress
              variant="determinate"
              value={currentEpisode.progressPercent}
              sx={{
                color: '#FF5722',
                '& .MuiCircularProgress-circle': {
                  strokeLinecap: 'round',
                },
              }}
              size={60}
              thickness={4}
            />
          </Box>

          <Stack spacing={1.5}>
            <Box>
              <Typography variant="body2" sx={{ color: '#FF5722', mb: 0.5 }}>
                Listening Stats
              </Typography>
              <Stack direction="row" justifyContent="space-between">
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  Total Hours
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                  {listeningStats.totalHours} hrs
                </Typography>
              </Stack>
              <Stack direction="row" justifyContent="space-between">
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  Episodes Completed
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFFFFF', fontWeight: 600 }}>
                  {listeningStats.episodesCompleted}
                </Typography>
              </Stack>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
